import React, {useState} from 'react';
import { submitReportApi, createSupportApi } from '../api/apiServices';
import { useNavigate } from 'react-router-dom';

export const ReportHazard = () => {
  const nav = useNavigate();
  const user = JSON.parse(localStorage.getItem('user'));
  const [form, setForm] = useState({ userId: user.id, reportType: 'Ngập lụt', description: '', latitude: 16.05, longitude: 108.2, dangerLevel: 'Cao'});

  const submit = async(e) => {
    e.preventDefault();
    await submitReportApi(form);
    alert('Báo cáo đã được gửi chờ duyệt!');
    nav('/');
  }

  return (
    <div className="container" style={{maxWidth:'600px'}}>
      <div className="card">
        <h2>Báo cáo Khu vực Nguy hiểm</h2>
        <form onSubmit={submit} style={{marginTop:'20px'}}>
          <div className="form-group"><label>Loại nguy hiểm</label><select onChange={e=>setForm({...form, reportType:e.target.value})}><option>Ngập lụt</option><option>Tắc đường</option><option>Sạt lở</option></select></div>
          <div className="form-group"><label>Mức độ nguy hiểm</label><select onChange={e=>setForm({...form, dangerLevel:e.target.value})}><option>Cao</option><option>Đặc biệt nghiêm trọng</option><option>Trung bình</option></select></div>
          <div className="form-group"><label>Mô tả chi tiết</label><textarea onChange={e=>setForm({...form, description:e.target.value})}/></div>
          <button className="btn btn-danger">Gửi báo cáo</button>
        </form>
      </div>
    </div>
  );
};

export const RequestSupport = () => {
  const nav = useNavigate();
  const user = JSON.parse(localStorage.getItem('user'));
  const [form, setForm] = useState({ userId: user.id, requestType: 'RESCUE', description: '', numberOfPeople: 1, latitude: 16.05, longitude: 108.2, priorityLevel: 'URGENT'});

  const REQUEST_TYPE_OPTIONS = [
    { label: "Cứu hộ", value: "RESCUE" },
    { label: "Y tế", value: "MEDICAL" },
    { label: "Lương thực", value: "FOOD" },
    { label: "Sơ tán", value: "EVACUATION" }
  ];

  const PRIORITY_OPTIONS = [
    { label: "Bình thường", value: "NORMAL" },
    { label: "Khẩn cấp", value: "URGENT" },
    { label: "Nguy kịch", value: "CRITICAL" }
  ];

  const submit = async(e) => {
    e.preventDefault();
    await createSupportApi(form);
    alert('Yêu cầu cứu hộ đã được gửi!');
    nav('/my-supports');
  }

  return (
    <div className="container" style={{maxWidth:'600px'}}>
      <div className="card">
        <h2>Yêu cầu Hỗ trợ / Khẩn cấp</h2>
        <form onSubmit={submit} style={{marginTop:'20px'}}>
          <div className="form-group">
            <label>Loại yêu cầu</label>
            <select value={form.requestType} onChange={e=>setForm({...form, requestType:e.target.value})}>
              {REQUEST_TYPE_OPTIONS.map(opt => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
            </select>
          </div>
          <div className="form-group">
            <label>Mức độ ưu tiên</label>
            <select value={form.priorityLevel} onChange={e=>setForm({...form, priorityLevel:e.target.value})}>
              {PRIORITY_OPTIONS.map(opt => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
            </select>
          </div>
          <div className="form-group"><label>Số người cần giúp</label><input type="number" value={form.numberOfPeople} onChange={e=>setForm({...form, numberOfPeople:e.target.value})}/></div>
          <div className="form-group"><label>Mô tả chi tiết / Details</label><textarea onChange={e=>setForm({...form, description:e.target.value})}/></div>
          <button className="btn">Gửi yêu cầu hỗ trợ ngay</button>
        </form>
      </div>
    </div>
  );
};
